import{c as t,Q as a,j as o,m as r}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"OckBench: Measuring the Efficiency of LLM Reasoning","description":"","frontmatter":{"title":"OckBench: Measuring the Efficiency of LLM Reasoning","authors":"Minyang Liu, Weijia Shi, Qiantong Xu, Luke Zettlemoyer, Wen-tau Yih, Sewon Min","published":"2025-11-07T00:00:00.000Z","source":"https://arxiv.org/abs/2511.05722"},"headers":[],"relativePath":"research/papers/2025-11-07-ock-bench-reasoning-efficiency-overthinking-2511-05722.md","filePath":"research/papers/2025-11-07-ock-bench-reasoning-efficiency-overthinking-2511-05722.md","lastUpdated":1779901665000}'),i={name:"research/papers/2025-11-07-ock-bench-reasoning-efficiency-overthinking-2511-05722.md"};function n(s,e,c,d,l,h){return a(),o("div",null,[...e[0]||(e[0]=[r(`<h1 id="ockbench-measuring-the-efficiency-of-llm-reasoning" tabindex="-1">OckBench: Measuring the Efficiency of LLM Reasoning <a class="header-anchor" href="#ockbench-measuring-the-efficiency-of-llm-reasoning" aria-label="Permalink to &quot;OckBench: Measuring the Efficiency of LLM Reasoning&quot;">​</a></h1><p><strong>Authors</strong>: Minyang Liu, Weijia Shi, Qiantong Xu, Luke Zettlemoyer, Wen-tau Yih, Sewon Min <strong>Published</strong>: November 7, 2025 <strong>Source</strong>: <a href="https://arxiv.org/abs/2511.05722" target="_blank" rel="noreferrer">https://arxiv.org/abs/2511.05722</a><strong>arXiv ID</strong>: 2511.05722 <strong>Categories</strong>: cs.CL, cs.AI, cs.LG</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>OckBench introduces the <strong>Overthinking Tax</strong> — the counterintuitive finding that smaller reasoning models can be more expensive than larger ones due to excessive token generation. A 7B open-source model is 57% more expensive than a 14B model when total cost (accuracy × token efficiency) is considered. Open-source models generate 5.1× more tokens than proprietary models for equivalent tasks. Introduces OckScore, a joint accuracy-efficiency metric: <code>S_ock = Accuracy − λ·log(T/C)</code>.</p><hr><h2 id="core-concept-the-overthinking-tax" tabindex="-1">Core Concept: The Overthinking Tax <a class="header-anchor" href="#core-concept-the-overthinking-tax" aria-label="Permalink to &quot;Core Concept: The Overthinking Tax&quot;">​</a></h2><p><strong>Occam&#39;s Razor principle</strong> applied to LLM reasoning: the simplest (most token-efficient) correct answer is preferred over verbose reasoning chains.</p><h3 id="the-paradox" tabindex="-1">The Paradox <a class="header-anchor" href="#the-paradox" aria-label="Permalink to &quot;The Paradox&quot;">​</a></h3><p>Smaller models attempt to compensate for lower accuracy by generating longer reasoning chains (&quot;thinking harder&quot;). This backfires:</p><table tabindex="0"><thead><tr><th>Model</th><th>Accuracy</th><th>Output Tokens (avg)</th><th>Cost per Correct Answer</th></tr></thead><tbody><tr><td>7B model</td><td>Lower</td><td><strong>3.13× more</strong> than 14B</td><td><strong>57% higher</strong> than 14B</td></tr><tr><td>14B model</td><td>Higher</td><td>Baseline</td><td>Baseline</td></tr></tbody></table><p>The 7B model&#39;s verbosity more than cancels its lower per-token cost advantage.</p><hr><h2 id="ockscore-joint-accuracy-efficiency-metric" tabindex="-1">OckScore: Joint Accuracy-Efficiency Metric <a class="header-anchor" href="#ockscore-joint-accuracy-efficiency-metric" aria-label="Permalink to &quot;OckScore: Joint Accuracy-Efficiency Metric&quot;">​</a></h2><h3 id="formula" tabindex="-1">Formula <a class="header-anchor" href="#formula" aria-label="Permalink to &quot;Formula&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>S_ock = Accuracy − λ · log(T / C)</span></span></code></pre></div><p>Where:</p><ul><li><code>Accuracy</code> = fraction of tasks correctly solved</li><li><code>T</code> = total output tokens generated</li><li><code>C</code> = calibration constant (10,000 tokens)</li><li><code>λ</code> = efficiency weight (10 by default)</li><li><code>log</code> = natural logarithm</li></ul><h3 id="interpretation" tabindex="-1">Interpretation <a class="header-anchor" href="#interpretation" aria-label="Permalink to &quot;Interpretation&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Scenario</th><th>OckScore</th></tr></thead><tbody><tr><td>High accuracy, low tokens</td><td>High (positive)</td></tr><tr><td>High accuracy, high tokens</td><td>Moderate (penalized)</td></tr><tr><td>Low accuracy, low tokens</td><td>Negative</td></tr><tr><td>Low accuracy, high tokens</td><td>Strongly negative</td></tr></tbody></table><p><strong>OckScore penalizes verbosity exponentially</strong> — a model that doubles its token count must also significantly improve accuracy to maintain the same score.</p><h3 id="calibration" tabindex="-1">Calibration <a class="header-anchor" href="#calibration" aria-label="Permalink to &quot;Calibration&quot;">​</a></h3><p>At <code>T = C = 10,000</code> tokens, the penalty term is 0. Models that solve a task in exactly 10,000 tokens are not penalized; those using fewer are rewarded, those using more are penalized.</p><hr><h2 id="open-source-vs-proprietary-the-verbosity-gap" tabindex="-1">Open-Source vs. Proprietary: The Verbosity Gap <a class="header-anchor" href="#open-source-vs-proprietary-the-verbosity-gap" aria-label="Permalink to &quot;Open-Source vs. Proprietary: The Verbosity Gap&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Category</th><th>Tokens (normalized to proprietary baseline)</th></tr></thead><tbody><tr><td><strong>Open-source models</strong></td><td><strong>5.1× proprietary baseline</strong></td></tr><tr><td>Proprietary models</td><td>1.0× (baseline)</td></tr></tbody></table><p><strong>Root cause hypothesis</strong>: Open-source reasoning models (trained with RL on step-by-step reasoning traces) are trained to be verbose because longer traces were historically higher quality. Proprietary models have been more aggressively optimized for token efficiency.</p><hr><h2 id="benchmark-results-top-models-by-ockscore" tabindex="-1">Benchmark Results: Top Models by OckScore <a class="header-anchor" href="#benchmark-results-top-models-by-ockscore" aria-label="Permalink to &quot;Benchmark Results: Top Models by OckScore&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Model</th><th>Accuracy</th><th>OckScore</th><th>Notes</th></tr></thead><tbody><tr><td>Claude Sonnet 4.5</td><td>High</td><td>High</td><td>Best proprietary OckScore</td></tr><tr><td>GPT-5</td><td>High</td><td>High</td><td>Comparable</td></tr><tr><td>Claude Haiku 4.5</td><td>Moderate</td><td>Moderate-High</td><td>Best efficiency ratio</td></tr><tr><td>Gemini 3.1 Flash</td><td>Moderate</td><td>Moderate</td><td>Token-efficient</td></tr><tr><td>Open-source 14B</td><td>Moderate</td><td>Moderate</td><td>Better than 7B</td></tr><tr><td>Open-source 7B</td><td>Lower</td><td><strong>Lowest</strong></td><td>Overthinking Tax severe</td></tr></tbody></table><hr><h2 id="task-categories-in-ockbench" tabindex="-1">Task Categories in OckBench <a class="header-anchor" href="#task-categories-in-ockbench" aria-label="Permalink to &quot;Task Categories in OckBench&quot;">​</a></h2><p>The benchmark spans reasoning tasks where efficiency matters:</p><table tabindex="0"><thead><tr><th>Category</th><th>Why Efficiency Matters</th></tr></thead><tbody><tr><td>Math reasoning</td><td>Step count ≠ accuracy; concise proofs better</td></tr><tr><td>Code generation</td><td>Verbose explanations before code waste tokens</td></tr><tr><td>Factual QA</td><td>Single-step retrieval; chains add noise</td></tr><tr><td>Logical puzzles</td><td>Direct solutions vs. exhaustive case enumeration</td></tr><tr><td>Summarization</td><td>Output length directly benchmarked</td></tr></tbody></table><hr><h2 id="overthinking-patterns-identified" tabindex="-1">Overthinking Patterns Identified <a class="header-anchor" href="#overthinking-patterns-identified" aria-label="Permalink to &quot;Overthinking Patterns Identified&quot;">​</a></h2><p>The paper categorizes specific overthinking behaviors:</p><h3 id="_1-unnecessary-verification-loops" tabindex="-1">1. Unnecessary Verification Loops <a class="header-anchor" href="#_1-unnecessary-verification-loops" aria-label="Permalink to &quot;1. Unnecessary Verification Loops&quot;">​</a></h3><p>Model solves the problem, then re-solves from scratch &quot;to verify,&quot; consuming 2× tokens.</p><h3 id="_2-exhaustive-case-enumeration" tabindex="-1">2. Exhaustive Case Enumeration <a class="header-anchor" href="#_2-exhaustive-case-enumeration" aria-label="Permalink to &quot;2. Exhaustive Case Enumeration&quot;">​</a></h3><p>When a few cases suffice, small models enumerate all edge cases regardless of relevance.</p><h3 id="_3-hedge-cascades" tabindex="-1">3. Hedge Cascades <a class="header-anchor" href="#_3-hedge-cascades" aria-label="Permalink to &quot;3. Hedge Cascades&quot;">​</a></h3><p>Excessive hedging (&quot;however,&quot; &quot;it&#39;s worth noting,&quot; &quot;one might argue&quot;) that adds tokens without information.</p><h3 id="_4-pre-answer-preamble" tabindex="-1">4. Pre-Answer Preamble <a class="header-anchor" href="#_4-pre-answer-preamble" aria-label="Permalink to &quot;4. Pre-Answer Preamble&quot;">​</a></h3><p>Restating the problem at length before answering (&quot;Let me think about this step by step. The question asks us to...&quot;).</p><h3 id="_5-post-answer-elaboration" tabindex="-1">5. Post-Answer Elaboration <a class="header-anchor" href="#_5-post-answer-elaboration" aria-label="Permalink to &quot;5. Post-Answer Elaboration&quot;">​</a></h3><p>Lengthy explanations after giving the correct answer (&quot;This is because...,&quot; &quot;In summary...,&quot; &quot;Note that...&quot;).</p><hr><h2 id="economic-implications" tabindex="-1">Economic Implications <a class="header-anchor" href="#economic-implications" aria-label="Permalink to &quot;Economic Implications&quot;">​</a></h2><h3 id="when-smaller-models-cost-more" tabindex="-1">When Smaller Models Cost More <a class="header-anchor" href="#when-smaller-models-cost-more" aria-label="Permalink to &quot;When Smaller Models Cost More&quot;">​</a></h3><p>A 7B model at $0.10/1M tokens vs. 14B at $0.25/1M tokens:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>7B: 100,000 output tokens × $0.10/1M = $0.010</span></span>
<span class="line"><span>14B: 32,000 output tokens × $0.25/1M = $0.008</span></span></code></pre></div><p>The 14B model is 20% cheaper in absolute cost despite costing 2.5× per token — because it generates 3.13× fewer tokens.</p><h3 id="budget-allocation-recommendation" tabindex="-1">Budget Allocation Recommendation <a class="header-anchor" href="#budget-allocation-recommendation" aria-label="Permalink to &quot;Budget Allocation Recommendation&quot;">​</a></h3><p>For cost-constrained deployments:</p><ul><li>Use larger proprietary models for accuracy-critical tasks (they&#39;re often cheaper on OckScore basis)</li><li>Avoid small open-source reasoning models for high-volume production (Overthinking Tax dominates)</li><li>Use Claude Haiku 4.5 for simple tasks where both accuracy and token efficiency are high</li></ul><hr><h2 id="λ-sensitivity-analysis" tabindex="-1">λ Sensitivity Analysis <a class="header-anchor" href="#λ-sensitivity-analysis" aria-label="Permalink to &quot;λ Sensitivity Analysis&quot;">​</a></h2><p>The paper tests sensitivity to the efficiency weight λ:</p><table tabindex="0"><thead><tr><th>λ Value</th><th>Ranking Change</th></tr></thead><tbody><tr><td>λ = 1</td><td>Minor reranking</td></tr><tr><td>λ = 10 (default)</td><td>Moderate reranking (shows Overthinking Tax)</td></tr><tr><td>λ = 50</td><td>Major reranking (punishes any verbosity severely)</td></tr></tbody></table><p>Default λ = 10 is calibrated to reflect real-world cost sensitivity where token costs are significant but accuracy is the primary objective.</p><hr><h2 id="workspace-relevance" tabindex="-1">Workspace Relevance <a class="header-anchor" href="#workspace-relevance" aria-label="Permalink to &quot;Workspace Relevance&quot;">​</a></h2><p>Directly actionable for model selection and prompt design:</p><ol><li><strong>Overthinking Tax for routing decisions</strong>: When using Claude Haiku 4.5 for simple tasks (<code>haiku-implementer</code> agent), verify it doesn&#39;t trigger overthinking on boundary tasks — if it generates 3× more tokens than expected, switch to Sonnet.</li><li><strong>OckScore for model selection</strong>: When comparing models for workspace tasks, weight token efficiency alongside accuracy. Claude Sonnet 4.5&#39;s high OckScore (good accuracy + low verbosity) validates its role as the primary workspace model.</li><li><strong>Open-source 5.1× verbosity</strong>: If evaluating open-source models for workspace sub-tasks (e.g., local inference), factor in the 5.1× token overhead — the actual cost may be comparable to or higher than proprietary API calls.</li><li><strong>Overthinking patterns → output discipline</strong>: The 5 overthinking patterns (hedge cascades, pre-answer preamble, post-answer elaboration) exactly match what <code>output-discipline.md</code> prohibits (&quot;不重述問題,&quot; &quot;無開場白,&quot; &quot;填充語禁止&quot;). OckBench validates these constraints economically.</li><li><strong>λ=10 calibration for budget tracking</strong>: The workspace&#39;s token budget rules (4K/task, 30K/session in <code>context-management.md</code>) implicitly implement an OckScore-like constraint — tasks that require excessive tokens are a signal to re-scope or compact.</li></ol>`,65)])])}const g=t(i,[["render",n]]);export{u as __pageData,g as default};
